class BIT:
    def __init__(self, n):
        self.n = n
        self.t = [0]*(n+1)
    def add(self, i, delta):
        while i <= self.n:
            self.t[i] += delta
            i += i & -i
    def sum(self, i):
        s = 0
        while i > 0:
            s += self.t[i]
            i -= i & -i
        return s

